// ============================================================================
// Multi-Topic Newsletter - Code Node (Simplified)
// ============================================================================
// Topics and questions now come pre-formatted from the database view
// ============================================================================

// Get webhook body
const webhookBody = $('Webhook').first().json.body;

// Get Supabase KB data (user-specific)
const kbData = $('Supabase_kb').first().json || {};

// Get Topics data (global - same for all users)
const topicsData = $('Supabase_topics').first().json || {};

// Default conversation state
const defaultState = {
  phase: 'topic_selection',
  selected_topics: [],
  current_topic_index: 0,
  current_question_index: 0,
  answers: {}
};

return [
  {
    json: {
      // Webhook identifiers
      user_id: webhookBody.user_id,
      user_mssg: webhookBody.user_mssg,
      session_id: webhookBody.session_id,
      agent_name: webhookBody.agent_name,
      timestamp_of_call_made: webhookBody.timestamp_of_call_made,
      request_id: webhookBody.request_id,

      // KB data (from client_agent_knowledge_base_view)
      knowledge_base: kbData.knowledge_base || '',
      knowledge_base_summary: (kbData.knowledge_base || '').substring(0, 2000),
      website_url: kbData.website_url || '',
      website_icon: kbData.favicon_url || '',
      communication_tone: kbData.communication_tone || 'professional',
      company_name: kbData.company_name || '',
      newsletter_instructions: kbData.newsletter_questions || '',

      // Topics data (from vw_newsletter_topics_for_llm - pre-formatted)
      available_topics_display: topicsData.available_topics_display || '',
      available_topics_text: topicsData.available_topics_text || '',
      topics_with_questions: JSON.stringify(topicsData.topics_with_questions || [], null, 2),
      topics_questions_formatted: topicsData.topics_questions_formatted || '',
      topic_code_map: topicsData.topic_code_map || {},
      total_topics: topicsData.total_topics || 7,

      // Conversation state
      conversation_state: JSON.stringify(defaultState, null, 2)
    }
  }
];

